"use client";

import { useState } from "react";
import Link from "next/link";
import type { BoardSummary } from "@/lib/types";
import { deleteBoard, renameBoard, toggleBoardPublic } from "@/lib/storage";

interface Props {
  board: BoardSummary;
  onDelete: (id: string) => void;
  onUpdate: () => void;
}

export default function BoardCard({ board, onDelete, onUpdate }: Props) {
  const [renaming, setRenaming] = useState(false);
  const [newTitle, setNewTitle] = useState(board.title);
  const [copied, setCopied] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);

  const updatedAt = new Date(board.updatedAt).toLocaleDateString("en-US", {
    month: "short",
    day: "numeric",
    year: "numeric",
  });

  function handleDelete() {
    if (confirm(`Delete "${board.title}"? This cannot be undone.`)) {
      deleteBoard(board.id);
      onDelete(board.id);
    }
    setMenuOpen(false);
  }

  function handleRenameSubmit(e: React.FormEvent) {
    e.preventDefault();
    const trimmed = newTitle.trim();
    if (trimmed && trimmed !== board.title) {
      renameBoard(board.id, trimmed);
      onUpdate();
    }
    setRenaming(false);
  }

  function handleTogglePublic() {
    toggleBoardPublic(board.id);
    onUpdate();
    setMenuOpen(false);
  }

  async function handleCopyShareLink() {
    const url = `${window.location.origin}/shared/${board.shareToken}`;
    await navigator.clipboard.writeText(url);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
    setMenuOpen(false);
  }

  return (
    <div className="group relative bg-white border border-gray-200 rounded-xl shadow-sm hover:shadow-md transition-shadow overflow-hidden flex flex-col">
      {/* Board preview area */}
      <Link
        href={`/board/${board.id}`}
        className="block flex-1 h-36 bg-gradient-to-br from-blue-50 to-indigo-100 flex items-center justify-center"
      >
        <svg
          xmlns="http://www.w3.org/2000/svg"
          className="h-12 w-12 text-blue-300"
          fill="none"
          viewBox="0 0 24 24"
          stroke="currentColor"
        >
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth={1.5}
            d="M4 5a1 1 0 011-1h14a1 1 0 011 1v2a1 1 0 01-1 1H5a1 1 0 01-1-1V5zM4 13a1 1 0 011-1h6a1 1 0 011 1v6a1 1 0 01-1 1H5a1 1 0 01-1-1v-6zM16 13a1 1 0 011-1h2a1 1 0 011 1v6a1 1 0 01-1 1h-2a1 1 0 01-1-1v-6z"
          />
        </svg>
      </Link>

      {/* Board info */}
      <div className="px-4 py-3 flex items-center justify-between gap-2">
        <div className="min-w-0 flex-1">
          {renaming ? (
            <form onSubmit={handleRenameSubmit} className="flex gap-2">
              <input
                autoFocus
                type="text"
                value={newTitle}
                onChange={(e) => setNewTitle(e.target.value)}
                className="flex-1 text-sm border border-blue-400 rounded px-2 py-0.5 focus:outline-none focus:ring-1 focus:ring-blue-500"
                onBlur={() => setRenaming(false)}
              />
            </form>
          ) : (
            <Link
              href={`/board/${board.id}`}
              className="block text-sm font-medium text-gray-900 truncate hover:text-blue-600"
            >
              {board.title}
            </Link>
          )}
          <p className="text-xs text-gray-400 mt-0.5">{updatedAt}</p>
        </div>

        {/* Action menu */}
        <div className="relative">
          <button
            onClick={() => setMenuOpen((v) => !v)}
            className="p-1.5 rounded-lg text-gray-400 hover:text-gray-700 hover:bg-gray-100 transition-colors"
            aria-label="Board actions"
          >
            <svg
              xmlns="http://www.w3.org/2000/svg"
              viewBox="0 0 20 20"
              fill="currentColor"
              className="w-4 h-4"
            >
              <path d="M10 3a1.5 1.5 0 110 3 1.5 1.5 0 010-3zM10 8.5a1.5 1.5 0 110 3 1.5 1.5 0 010-3zM11.5 15.5a1.5 1.5 0 10-3 0 1.5 1.5 0 003 0z" />
            </svg>
          </button>

          {menuOpen && (
            <>
              {/* Backdrop */}
              <div
                className="fixed inset-0 z-40"
                onClick={() => setMenuOpen(false)}
              />
              <div className="absolute right-0 bottom-full mb-1 z-50 bg-white border border-gray-200 rounded-lg shadow-lg py-1 w-44 text-sm">
                <button
                  onClick={() => {
                    setRenaming(true);
                    setMenuOpen(false);
                  }}
                  className="w-full text-left px-4 py-2 hover:bg-gray-50 text-gray-700"
                >
                  Rename
                </button>
                <button
                  onClick={handleTogglePublic}
                  className="w-full text-left px-4 py-2 hover:bg-gray-50 text-gray-700"
                >
                  {board.isPublic ? "Make Private" : "Make Public"}
                </button>
                {board.isPublic && (
                  <button
                    onClick={handleCopyShareLink}
                    className="w-full text-left px-4 py-2 hover:bg-gray-50 text-gray-700"
                  >
                    {copied ? "✓ Copied!" : "Copy Share Link"}
                  </button>
                )}
                <hr className="my-1" />
                <button
                  onClick={handleDelete}
                  className="w-full text-left px-4 py-2 hover:bg-red-50 text-red-600"
                >
                  Delete
                </button>
              </div>
            </>
          )}
        </div>
      </div>

      {/* Public badge */}
      {board.isPublic && (
        <span className="absolute top-2 left-2 bg-green-500 text-white text-xs px-2 py-0.5 rounded-full font-medium">
          Public
        </span>
      )}
    </div>
  );
}
