"use client";

import { useState, useEffect, useCallback } from "react";
import { useRouter } from "next/navigation";
import type { BoardSummary } from "@/lib/types";
import { getBoards, createBoard } from "@/lib/storage";
import BoardCard from "./BoardCard";
import CreateBoardModal from "./CreateBoardModal";

export default function Dashboard() {
  const router = useRouter();
  const [boards, setBoards] = useState<BoardSummary[]>([]);
  const [showModal, setShowModal] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");

  const loadBoards = useCallback(() => {
    setBoards(getBoards());
  }, []);

  useEffect(() => {
    loadBoards();
  }, [loadBoards]);

  function handleCreateBoard(title: string) {
    const board = createBoard(title);
    setShowModal(false);
    router.push(`/board/${board.id}`);
  }

  const filteredBoards = boards.filter((b) =>
    b.title.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">
            My Boards
            <span className="font-arabic text-blue-600 mr-2 text-xl">
              {" "}
              لوحاتي
            </span>
          </h1>
          <p className="text-gray-500 text-sm mt-1">
            {boards.length === 0
              ? "Create your first board to get started"
              : `${boards.length} board${boards.length !== 1 ? "s" : ""}`}
          </p>
        </div>
        <button
          onClick={() => setShowModal(true)}
          className="inline-flex items-center gap-2 px-5 py-2.5 bg-blue-600 hover:bg-blue-700 text-white text-sm font-medium rounded-lg transition-colors shadow-sm"
        >
          <svg
            xmlns="http://www.w3.org/2000/svg"
            viewBox="0 0 20 20"
            fill="currentColor"
            className="w-4 h-4"
          >
            <path d="M10.75 4.75a.75.75 0 00-1.5 0v4.5h-4.5a.75.75 0 000 1.5h4.5v4.5a.75.75 0 001.5 0v-4.5h4.5a.75.75 0 000-1.5h-4.5v-4.5z" />
          </svg>
          New Board
        </button>
      </div>

      {/* Search */}
      {boards.length > 0 && (
        <div className="mb-6">
          <input
            type="search"
            placeholder="Search boards… / ابحث عن لوحة"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full sm:w-72 px-4 py-2 border border-gray-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          />
        </div>
      )}

      {/* Board grid */}
      {filteredBoards.length > 0 ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-5">
          {filteredBoards.map((board) => (
            <BoardCard
              key={board.id}
              board={board}
              onDelete={loadBoards}
              onUpdate={loadBoards}
            />
          ))}
        </div>
      ) : boards.length === 0 ? (
        /* Empty state */
        <div className="text-center py-20">
          <div className="inline-flex items-center justify-center w-20 h-20 bg-blue-50 rounded-2xl mb-6">
            <svg
              xmlns="http://www.w3.org/2000/svg"
              className="h-10 w-10 text-blue-400"
              fill="none"
              viewBox="0 0 24 24"
              stroke="currentColor"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={1.5}
                d="M9 17V7m0 10a2 2 0 01-2 2H5a2 2 0 01-2-2V7a2 2 0 012-2h2a2 2 0 012 2m0 10a2 2 0 002 2h2a2 2 0 002-2M9 7a2 2 0 012-2h2a2 2 0 012 2m0 10V7m0 10a2 2 0 002 2h2a2 2 0 002-2V7a2 2 0 00-2-2h-2a2 2 0 00-2 2"
              />
            </svg>
          </div>
          <h2 className="text-xl font-semibold text-gray-900 mb-2">
            No boards yet
          </h2>
          <p className="text-gray-500 mb-8 max-w-sm mx-auto">
            Create your first collaborative whiteboard and start drawing with
            Arabic handwriting fonts.
          </p>
          <button
            onClick={() => setShowModal(true)}
            className="inline-flex items-center gap-2 px-6 py-3 bg-blue-600 hover:bg-blue-700 text-white font-medium rounded-xl transition-colors shadow-sm"
          >
            <svg
              xmlns="http://www.w3.org/2000/svg"
              viewBox="0 0 20 20"
              fill="currentColor"
              className="w-5 h-5"
            >
              <path d="M10.75 4.75a.75.75 0 00-1.5 0v4.5h-4.5a.75.75 0 000 1.5h4.5v4.5a.75.75 0 001.5 0v-4.5h4.5a.75.75 0 000-1.5h-4.5v-4.5z" />
            </svg>
            Create your first board
          </button>
        </div>
      ) : (
        /* No search results */
        <div className="text-center py-12">
          <p className="text-gray-400">
            No boards matching &ldquo;{searchQuery}&rdquo;
          </p>
        </div>
      )}

      {/* Create board modal */}
      {showModal && (
        <CreateBoardModal
          onConfirm={handleCreateBoard}
          onClose={() => setShowModal(false)}
        />
      )}
    </div>
  );
}
